previewCss:
.darma-loader-uiverse-propeller-tick-spinner__spinner { position: relative; width: 34px; height: 34px; }
.darma-loader-uiverse-propeller-tick-spinner__spinner div {
  position: absolute;
  left: 50%;
  top: 50%;
  width: 4px;
  height: 18px;
  border-radius: 4px;
  background: var(--loader-color, #000000);
  transform: rotate(calc(var(--rotation) * 1deg)) translate(0, calc(var(--translation) * 1%));
  animation: darma-loader-uiverse-propeller-tick-spinner-propellerTick 1s calc(var(--delay) * 1s) infinite ease;
  transform-origin: 50% 0;
}
@keyframes darma-loader-uiverse-propeller-tick-spinner-propellerTick { 0%, 100% { opacity: .15; } 50% { opacity: 1; } }

